import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/SupabaseContext';

export default function ForgotPasswordPage() {
  const { resetPassword } = useAuth();
  const [email, setEmail] = useState('');
  const [sent, setSent] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError('');
    setLoading(true);
    const { error: err } = await resetPassword(email);
    setLoading(false);
    if (err) {
      setError(err);
    } else {
      setSent(true);
    }
  }

  return (
    <div style={{ maxWidth: '420px', margin: '4rem auto', padding: '0 1.5rem' }}>
      <div className="glass-panel" style={{ padding: '2.5rem 2rem', textAlign: 'center' }}>
        <h2 style={{ fontSize: '1.5rem', marginBottom: '0.5rem' }}>
          <i className="fa-solid fa-key" style={{ color: 'var(--primary-color)' }} /> Reset Password
        </h2>

        {sent ? (
          <>
            <p style={{ color: 'var(--text-secondary)', lineHeight: 1.6, margin: '1rem 0 1.5rem' }}>
              Check your email! We sent a password reset link to <strong style={{ color: 'var(--text-primary)' }}>{email}</strong>.
            </p>
            <Link to="/login" className="btn secondary-btn large-action-btn" style={{ textDecoration: 'none' }}>
              Back to Login
            </Link>
          </>
        ) : (
          <>
            <p style={{ color: 'var(--text-secondary)', marginBottom: '1.5rem', lineHeight: 1.5 }}>
              Enter your email and we'll send you a link to reset your password.
            </p>

            <form onSubmit={handleSubmit} style={{ textAlign: 'left' }}>
              <div style={{ marginBottom: '1rem' }}>
                <label htmlFor="reset-email" style={{ fontSize: '0.9rem', color: 'var(--text-secondary)', marginBottom: '0.3rem', display: 'block' }}>
                  Email
                </label>
                <input
                  id="reset-email"
                  type="email"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  placeholder="you@example.com"
                  required
                  autoComplete="email"
                />
              </div>

              {error && (
                <p style={{ color: '#ef4444', fontSize: '0.82rem', marginBottom: '1rem' }}>{error}</p>
              )}

              <button type="submit" disabled={loading} className="btn secondary-btn large-action-btn">
                {loading ? 'Sending...' : 'Send Reset Link'}
              </button>
            </form>

            <p style={{ marginTop: '1.5rem', fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
              Remember your password?{' '}
              <Link to="/login" style={{ color: 'var(--primary-color)', fontWeight: 600 }}>
                Sign In
              </Link>
            </p>
          </>
        )}
      </div>
    </div>
  );
}
